/// <summary>
/// extension class for class <c>CustVendSettle_Vend</c>
/// </summary>
[ExtensionOf(Classstr(CustVendSettle_Vend))]
internal final class ETGCustVendSettle_Vend_Extension
{
    public container con;
}

Method.Source:
public void updateTransOpen(CustVendTrans _custVendTrans, CustVendTransOpen _custVendTransOpen)
{
    next updateTransOpen( _custVendTrans,  _custVendTransOpen);

    //CS, DLT, 31012025, vendor payment journal integration with fusion
    if (this.moduleCustVend() == ModuleCustVend::Vend && BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGVendPaymPostedBusinessEvent)))
    {
        VendTrans vendTransETG;
        select firstonly vendTransETG where vendTransETG.Voucher == _custVendTrans.Voucher;
        if (vendTransETG && (vendTransETG.TransType == LedgerTransType::Payment || vendTransETG.TransType == LedgerTransType::None))
        {
            con +=[_custVendTrans.Voucher];
        }
    }
    //CE, DLT, 31012025, vendor payment journal integration with fusion
}

public void settleNow(dataAreaId _company, tableId _tableId, recId _recId, boolean _balancePostingProfile)
{
    next settleNow( _company,  _tableId,  _recId,  _balancePostingProfile);

    //CS, DLT, 31012025, vendor payment journal integration with fusion
    if (BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGVendPaymPostedBusinessEvent)))
    {
        container cont = this.getVouchers();

        if(this.moduleCustVend() == ModuleCustVend::Vend)
        {
            ETGCustVendPaymSettlement::sendPaymentVend(cont);
        }
    }
    //CE, DLT, 31012025, vendor payment journal integration with fusion
}
